const item = $input.first();
const body = item?.json?.body || {};
const errors = [];

function text(name) {
  return String(body[name] ?? '').trim();
}
function optionalBoolean(name) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return true;
  const v = String(raw).trim().toLowerCase();
  return ['true','false','1','0','yes','no','si','s','n','on','off'].includes(v);
}
function optionalNumber(name, min, max) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return true;
  const n = Number(raw);
  return Number.isFinite(n) && n >= min && n <= max;
}

if (!text('email_to')) {
  errors.push('email_to es obligatorio para llamadas webhook.');
}

for (const name of ['include_attachment','include_detail','include_summary','include_operational_notes','send_email','send_when_no_records']) {
  if (!optionalBoolean(name)) errors.push(`${name} debe ser booleano compatible: true/false, 1/0, si/no.`);
}
if (!optionalNumber('stale_days', 1, 3650)) errors.push('stale_days debe ser numerico entre 1 y 3650.');

const valid = errors.length === 0;
return [{
  json: {
    ...(item.json || {}),
    webhook_contract: {
      valid,
      status_code: valid ? 202 : 400,
      message: valid ? 'Workflow accepted' : errors.join(' '),
      errors,
    },
  },
  binary: item.binary,
}];

const item = $input.first();
const json = item?.json || {};
if (!json.webhook_contract?.valid) return [];
const { webhook_contract, ...cleanJson } = json;
return [{ json: cleanJson, binary: item.binary }];

const base = $input.first()?.json || {};
const trigger = $('SetTrigger - Flujo').first()?.json || {};

function normalizeBoolean(value, fallback) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function parseList(value, fallback = []) {
  const raw = value === undefined || value === null || value === '' ? fallback : value;
  if (Array.isArray(raw)) return raw.map(v => String(v).trim()).filter(Boolean);
  return String(raw)
    .split(/[;,\n|]+/)
    .map(v => v.trim())
    .filter(Boolean);
}

const flags = { ...(base.flags || {}) };
for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','send_when_no_records']) {
  flags[key] = normalizeBoolean(trigger[key] ?? base[key], flags[key] ?? true);
}

const config = {
  nombreReporte: 'ad_informe_equipos_servidores_gf_chile',
  zonaHoraria: trigger.timezone || base.timezone || 'America/Santiago',
  prefixes: {
    endpoint: 'GF0',
    servidor: 'GFPE',
  },
  ldap: {
    baseDn: trigger.ldap_base_dn,
    filter: trigger.ldap_filter,
    attributes: trigger.ldap_attributes,
    includedOus: parseList(trigger.ldap_included_ous, ['Computers','Disable Device','Servers','Servers AWS']),
  },
  mail: {
    from: trigger.email_from,
    to: trigger.email_to,
    cc: trigger.email_cc || '',
    bcc: trigger.email_bcc || '',
    subjectPrefix: trigger.email_subject || 'Informe Equipos y servidores AD GF Chile',
    enviarSiempre: true,
  },
};

const errors = [];
function required(path, value) {
  if (value === undefined || value === null || String(value).trim() === '') errors.push(`Parametro obligatorio no informado: ${path}`);
}
required('ldap_base_dn', config.ldap.baseDn);
required('ldap_filter', config.ldap.filter);
required('ldap_attributes', config.ldap.attributes);
if (!config.ldap.includedOus.length) errors.push('Parametro obligatorio no informado: ldap_included_ous');
required('email_from', config.mail.from);
required('email_to', config.mail.to);

const setMixed = {
  ...base,
  ...trigger,
  flags,
  config,
  config_source: 'SetBase + SetTrigger + Config Reporte',
  config_validated: errors.length === 0,
  config_message: errors.length === 0 ? 'Parametros de configuracion validados' : errors.join(' | '),
};
flags.include_itop_button_footer = false;
for (const [key, value] of Object.entries(flags)) setMixed[key] = value;
if (!setMixed.config_validated) throw new Error(setMixed.config_message);
return [{ json: setMixed }];

const config = $('Config Reporte').first().json || {};
const cfg = config.config || {};
const flags = config.flags || {};
const timezone = cfg.zonaHoraria || config.timezone || 'America/Santiago';
const company = String(config.Company || config.company || 'TecnoComp').trim();
const organization = String(config.itop_organization || 'GF Chile').trim();
const now = new Date();

function clean(v) {
  if (v === undefined || v === null) return '';
  if (Array.isArray(v)) return v.map(clean).filter(Boolean).join('; ');
  return String(v).trim();
}
function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}
function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}
function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}
function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      continue;
    }
    if (Array.isArray(j)) { rows.push(...j); continue; }
    rows.push(j);
  }
  return rows;
}
function windowsFileTimeToDate(value) {
  const raw = clean(value);
  if (!raw || raw === '0' || raw === '9223372036854775807') return null;
  const n = Number(raw);
  if (!Number.isFinite(n) || n <= 0) return null;
  const ms = Math.floor(n / 10000) - 11644473600000;
  const d = new Date(ms);
  return Number.isNaN(d.getTime()) ? null : d;
}
function parseMaybeDate(value) {
  if (!value) return null;
  if (value instanceof Date) return Number.isNaN(value.getTime()) ? null : value;
  const raw = clean(value);
  if (!raw) return null;
  if (/^\d{12,}$/.test(raw)) return windowsFileTimeToDate(raw);
  const normalized = raw.includes('T') ? raw : raw.replace(' ', 'T');
  const d = new Date(normalized);
  return Number.isNaN(d.getTime()) ? null : d;
}
function fmtDateTime(value) {
  const d = value instanceof Date ? value : parseMaybeDate(value);
  if (!d) return '-';
  return d.toLocaleString('es-CL', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
}
function dnWithoutDomain(dn) {
  return clean(dn).split(',').filter(p => !/^DC=/i.test(p)).join(',');
}
function relativeOuFromDn(dn) {
  const parts = clean(dn).split(',').filter(Boolean);
  const ouParts = parts.filter(p => /^OU=/i.test(p));
  const sitesIndex = ouParts.findIndex(p => /^OU=SITES_CHILE$/i.test(p));
  const relevant = sitesIndex >= 0 ? ouParts.slice(0, sitesIndex + 1) : ouParts;
  return relevant.join(',');
}
function escapeRegex(value) {
  return String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}
function includedOusConfig() {
  const list = cfg.ldap?.includedOus;
  if (Array.isArray(list) && list.length) return list.map(clean).filter(Boolean);
  const raw = clean(config.ldap_included_ous || 'Computers,Disable Device,Servers,Servers AWS');
  return raw.split(/[;,\n|]+/).map(v => v.trim()).filter(Boolean);
}
function matchesIncludedOu(dn, includedOus) {
  const text = clean(dn);
  if (!text) return false;
  return includedOus.some(ou => {
    const pattern = new RegExp(`OU=${escapeRegex(ou)},OU=SITES_CHILE`, 'i');
    return pattern.test(text);
  });
}
function matchedOu(dn, includedOus) {
  const text = clean(dn);
  const found = includedOus.find(ou => new RegExp(`OU=${escapeRegex(ou)},OU=SITES_CHILE`, 'i').test(text));
  return found || '';
}
function isComputerRecord(row) {
  const objectClass = clean(getField(row, ['objectClass', 'objectclass'], '')).toLowerCase();
  const objectCategory = clean(getField(row, ['objectCategory', 'objectcategory'], '')).toLowerCase();
  const sam = clean(getField(row, ['sAMAccountName', 'samaccountname'], ''));
  const uac = clean(getField(row, ['userAccountControl', 'useraccountcontrol'], ''));
  const dns = clean(getField(row, ['dNSHostName', 'dnshostname'], ''));
  if (objectClass.includes('computer') || objectCategory.includes('computer')) return true;
  if (sam.endsWith('$')) return true;
  if (uac || dns) return true;
  return false;
}
function statusFromUac(uac) {
  const n = Number(clean(uac) || 0);
  return (n & 2) === 2 ? 'INACTIVO' : 'ACTIVO';
}
function collectIps(row) {
  const values = [];
  for (const field of ['ipv4Address', 'ipHostNumber', 'networkAddress', 'ipaddress', 'ip']) {
    const raw = getField(row, [field], '');
    if (Array.isArray(raw)) values.push(...raw.map(clean).filter(Boolean));
    else if (clean(raw)) values.push(clean(raw));
  }
  const joined = values.join('; ');
  const matches = joined.match(/\b(?:\d{1,3}\.){3}\d{1,3}\b/g) || values;
  return [...new Set(matches.map(clean).filter(Boolean))].join(', ');
}
function normalizeHostname(row) {
  const name = clean(getField(row, ['name', 'cn'], ''));
  const dns = clean(getField(row, ['dNSHostName', 'dnshostname'], ''));
  const sam = clean(getField(row, ['sAMAccountName', 'samaccountname'], '')).replace(/\$$/, '');
  const host = name || sam || (dns ? dns.split('.')[0] : '');
  return clean(host).toUpperCase();
}
function tipoPorHostname(hostname) {
  const value = clean(hostname).toUpperCase();
  if (value.startsWith('GFPE')) return 'SERVIDOR';
  if (value.startsWith('GF0')) return 'ENDPOINT';
  return 'REVISAR';
}
function endpointSubtipo(hostname, tipo) {
  if (tipo !== 'ENDPOINT') return tipo === 'SERVIDOR' ? 'Servidor' : 'Validar';
  const value = clean(hostname).toUpperCase();
  if (value.endsWith('-L')) return 'Laptop';
  if (value.endsWith('-D')) return 'Desktop';
  if (value.endsWith('-T')) return 'Tablet';
  if (value.endsWith('-V')) return 'Virtual';
  return 'Validar';
}
function adObservation(row) {
  const description = clean(getField(row, ['description'], ''));
  const info = clean(getField(row, ['info'], ''));
  const values = [description, info].filter(Boolean);
  return values.length ? values.join(' | ') : '-';
}
function revisionText(record) {
  const notes = [];
  if (record.tipo === 'REVISAR') notes.push('Hostname fuera de nomenclatura esperada GF0/GFPE');
  if (record.tipo === 'ENDPOINT' && record.subtipo === 'Validar') notes.push('Endpoint sin sufijo normalizado -L/-D/-T/-V');
  if (!record.lastLogonDate) notes.push('Sin LastLogon informado');
  if (record.status === 'INACTIVO') notes.push('Cuenta de equipo deshabilitada en AD');
  return notes.join(' | ') || 'Sin observaciones de control';
}
function td(value, align = 'left') {
  return `<td align="${align}" style="font-size:12px;line-height:16px;color:#1f2937;padding:8px 7px;border-bottom:1px solid #edf2f7;vertical-align:top;">${value}</td>`;
}
function th(text, align = 'left') {
  return `<th align="${align}" style="background-color:#f8fafc;color:#334155;font-size:11px;line-height:15px;font-weight:bold;text-align:${align};padding:8px 7px;border-bottom:1px solid #dbe3ec;white-space:nowrap;">${escapeHtml(text)}</th>`;
}
function displayTipo(tipo) {
  if (tipo === 'SERVIDOR') return 'Servidor';
  if (tipo === 'ENDPOINT') return 'Endpoint';
  return 'Revisar';
}
function displayStatus(status) {
  return status === 'ACTIVO' ? 'Activo' : 'Inactivo';
}
function recordRow(r) {
  return `<tr>
    ${td(`<strong>${escapeHtml(r.hostname || '-')}</strong>`)}
    ${td(escapeHtml(displayTipo(r.tipo)))}
    ${td(escapeHtml(r.subtipo || '-'))}
    ${td(escapeHtml(displayStatus(r.status)))}
    ${td(escapeHtml(r.lastLogon))}
    ${td(escapeHtml(r.observacionesAd))}
    ${td(escapeHtml(r.ouRelativa))}
  </tr>`;
}
function tableForRecords(records) {
  if (!records.length) return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="width:100%;border:1px solid #dbe3ec;margin-bottom:14px;"><tbody><tr>${td('Sin registros para este bloque.', 'left')}</tr></tbody></table>`;
  return `<div style="width:100%;overflow-x:auto;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="width:100%;border:1px solid #dbe3ec;margin-bottom:14px;">
    <thead><tr>${th('Hostname')}${th('Tipo')}${th('Subtipo')}${th('Estado')}${th('LastLogon')}${th('Observacion')}${th('OU')}</tr></thead>
    <tbody>${records.map(recordRow).join('')}</tbody>
  </table></div>`;
}
function subsection(title, records) {
  return `<div style="font-size:14px;line-height:20px;font-weight:bold;color:#0f172a;margin:14px 0 6px 0;">${escapeHtml(title)} <span style="color:#64748b;font-weight:normal;">(${records.length})</span></div>${tableForRecords(records)}`;
}
function groupBySubtype(records) {
  const order = ['Servidor', 'Laptop', 'Desktop', 'Tablet', 'Virtual', 'Validar'];
  return order
    .map(subtipo => [subtipo, records.filter(r => r.subtipo === subtipo)])
    .filter(([, list]) => list.length > 0);
}
function statusBlock(title, records) {
  const servidores = records.filter(r => r.tipo === 'SERVIDOR');
  const endpoints = records.filter(r => r.tipo === 'ENDPOINT');
  let html = `<div style="font-size:16px;line-height:22px;font-weight:bold;color:#0f172a;margin:20px 0 8px 0;">${escapeHtml(title)} <span style="color:#64748b;font-weight:normal;">(${records.length})</span></div>`;
  html += subsection('Servidores', servidores);
  for (const [subtipo, list] of groupBySubtype(endpoints)) html += subsection(`Endpoint - ${subtipo}`, list);
  return html;
}
function priorityBlock(title, description, records) {
  let html = `<div style="font-size:16px;line-height:22px;font-weight:bold;color:#0f172a;margin:20px 0 8px 0;">${escapeHtml(title)} <span style="color:#64748b;font-weight:normal;">(${records.length})</span></div>`;
  if (description) html += `<div style="font-size:12px;line-height:18px;color:#64748b;margin-bottom:8px;">${escapeHtml(description)}</div>`;
  html += tableForRecords(records);
  return html;
}

const includedOus = includedOusConfig();
const rawRows = flattenInput($input.all());
const records = rawRows.filter((row) => {
  const f = row.fields || row;
  const dn = clean(getField(f, ['distinguishedName', 'dn'], ''));
  return isComputerRecord(f) && matchesIncludedOu(dn, includedOus);
}).map((row) => {
  const f = row.fields || row;
  const hostname = normalizeHostname(f);
  const lastLogonDate = parseMaybeDate(getField(f, ['lastLogonTimestamp', 'lastlogontimestamp', 'lastLogon', 'lastlogon'], ''));
  const tipo = tipoPorHostname(hostname);
  const subtipo = endpointSubtipo(hostname, tipo);
  const status = statusFromUac(getField(f, ['userAccountControl', 'useraccountcontrol'], ''));
  const dn = clean(getField(f, ['distinguishedName', 'dn'], ''));
  const record = {
    hostname,
    tipo,
    subtipo,
    status,
    lastLogonDate,
    lastLogon: fmtDateTime(lastLogonDate),
    observacionesAd: adObservation(f),
    ouRelativa: relativeOuFromDn(dn),
    ouAbsoluta: dnWithoutDomain(dn),
    distinguishedName: dn,
    dn,
    scopeOu: matchedOu(dn, includedOus),
    ip: collectIps(f),
    os: clean(getField(f, ['operatingSystem', 'operatingsystem'], '')),
    osVersion: clean(getField(f, ['operatingSystemVersion', 'operatingsystemversion'], '')),
    dnsHostName: clean(getField(f, ['dNSHostName', 'dnshostname'], '')),
    samAccountName: clean(getField(f, ['sAMAccountName', 'samaccountname'], '')),
    managedBy: clean(getField(f, ['managedBy', 'managedby'], '')),
    location: clean(getField(f, ['location'], '')),
    whenChanged: fmtDateTime(parseMaybeDate(getField(f, ['whenChanged', 'whenchanged'], ''))),
    whenCreated: fmtDateTime(parseMaybeDate(getField(f, ['whenCreated', 'whencreated'], ''))),
  };
  record.revision = revisionText(record);
  return record;
}).sort((a, b) => {
  const topOrder = { REVISAR: 0, VALIDAR: 1, ACTIVO: 2, INACTIVO: 3 };
  const typeOrder = { SERVIDOR: 0, ENDPOINT: 1, REVISAR: 2 };
  const subtypeOrder = { Servidor: 0, Laptop: 1, Desktop: 2, Tablet: 3, Virtual: 4, Validar: 5 };
  const group = (r) => r.tipo === 'REVISAR' ? 'REVISAR' : (r.subtipo === 'Validar' ? 'VALIDAR' : r.status);
  return (topOrder[group(a)] - topOrder[group(b)])
    || (typeOrder[a.tipo] - typeOrder[b.tipo])
    || (subtypeOrder[a.subtipo] - subtypeOrder[b.subtipo])
    || a.hostname.localeCompare(b.hostname);
});

const totalRecords = records.length;
const totalServidores = records.filter(r => r.tipo === 'SERVIDOR').length;
const totalEndpoints = records.filter(r => r.tipo === 'ENDPOINT').length;
const totalRevisar = records.filter(r => r.tipo === 'REVISAR').length;
const totalActivos = records.filter(r => r.status === 'ACTIVO').length;
const totalInactivos = records.filter(r => r.status === 'INACTIVO').length;
const totalLaptop = records.filter(r => r.subtipo === 'Laptop').length;
const totalDesktop = records.filter(r => r.subtipo === 'Desktop').length;
const totalTablet = records.filter(r => r.subtipo === 'Tablet').length;
const totalVirtual = records.filter(r => r.subtipo === 'Virtual').length;
const totalValidar = records.filter(r => r.tipo !== 'REVISAR' && r.subtipo === 'Validar').length;
const totalClasificados = records.filter(r => r.tipo !== 'REVISAR' && r.subtipo !== 'Validar').length;

const revisarNomenclatura = records.filter(r => r.tipo === 'REVISAR');
const validar = records.filter(r => r.tipo !== 'REVISAR' && r.subtipo === 'Validar');
const activos = records.filter(r => r.tipo !== 'REVISAR' && r.subtipo !== 'Validar' && r.status === 'ACTIVO');
const inactivos = records.filter(r => r.tipo !== 'REVISAR' && r.subtipo !== 'Validar' && r.status === 'INACTIVO');

const detailSection = `<div style="font-size:16px;line-height:22px;font-weight:bold;color:#0f172a;margin:20px 0 8px 0;">Inventario AD priorizado</div>
<div style="font-size:12px;line-height:18px;color:#64748b;margin-bottom:8px;">Vista ejecutiva para ordenar acciones de control: primero registros que requieren revision o validacion, luego equipos activos e inactivos ya clasificados. La OU se presenta como ruta relativa para facilitar lectura; el CSV adjunto mantiene el detalle extendido para seguimiento.</div>
${priorityBlock('Revisar nomenclatura', 'Equipos que deben revisarse antes de considerarse dentro del estandar de inventario.', revisarNomenclatura)}
${priorityBlock('Validar clasificacion', 'Endpoints que requieren confirmacion de clasificacion para completar la lectura operacional del inventario.', validar)}
${statusBlock('Activos clasificados', activos)}
${statusBlock('Inactivos clasificados', inactivos)}`;

const csvHeaders = [
  'Hostname','Tipo','Subtipo','Status','LastLogon','Observaciones AD','OU Relativa','OU Absoluta','DistinguishedName','OU Alcance','IP','Sistema Operativo','Version SO','DNSHostName','SamAccountName','ManagedBy','Location','WhenChanged','WhenCreated','Revision'
];
const csvRows = records.map(r => [
  r.hostname, r.tipo, r.subtipo, r.status, r.lastLogon, r.observacionesAd, r.ouRelativa, r.ouAbsoluta, r.distinguishedName, r.scopeOu, r.ip, r.os, r.osVersion, r.dnsHostName, r.samAccountName, r.managedBy, r.location, r.whenChanged, r.whenCreated, r.revision
]);
const csvContent = '\uFEFF' + [csvHeaders.map(csvEscape).join(';'), ...csvRows.map(row => row.map(csvEscape).join(';'))].join('\r\n');
const generatedAt = now.toLocaleString('es-CL', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
const generatedAtFile = now.toISOString().replace(/[:.]/g, '-').replace('T', '_').slice(0, 19);
const subjectBase = String(cfg.mail?.subjectPrefix || config.email_subject || 'Informe Equipos y servidores AD GF Chile').trim();

return [{
  json: {
    flags,
    report_template_key: config.report_template_key,
    include_attachment: flags.include_attachment ?? config.include_attachment,
    include_detail: flags.include_detail ?? config.include_detail,
    include_summary: flags.include_summary ?? config.include_summary,
    include_operational_notes: flags.include_operational_notes ?? config.include_operational_notes,
    operational_notes: 'Este informe facilita la depuracion del inventario AD, destacando brechas de nomenclatura, vigencia y clasificacion para priorizar acciones de normalizacion, auditoria y conciliacion con CMDB.',
    email_from: cfg.mail?.from || config.email_from,
    email_to: cfg.mail?.to || config.email_to,
    email_cc: cfg.mail?.cc || config.email_cc || '',
    email_bcc: cfg.mail?.bcc || config.email_bcc || '',
    email_subject: organization ? `${subjectBase} - ${organization}` : subjectBase,
    company,
    Company: company,
    itop_organization: organization,
    generated_at: generatedAt,
    ldap_base_dn: cfg.ldap?.baseDn || config.ldap_base_dn,
    ldap_included_ous: includedOus.join(', '),
    total_raw_ldap: String(rawRows.length),
    total_records: String(totalRecords),
    total_equipos: String(totalRecords),
    total_servidores: String(totalServidores),
    total_endpoint: String(totalEndpoints),
    total_revisar: String(totalRevisar),
    total_activos: String(totalActivos),
    total_inactivos: String(totalInactivos),
    total_laptop: String(totalLaptop),
    total_desktop: String(totalDesktop),
    total_tablet: String(totalTablet),
    total_virtual: String(totalVirtual),
    total_validar: String(totalValidar),
    total_clasificados: String(totalClasificados),
    detail_section: detailSection,
    hayRegistros: totalRecords > 0,
    csv_filename: `informe_equipos_servidores_ad_gf_chile_${generatedAtFile}.csv`,
  },
  binary: {
    csv: {
      data: Buffer.from(csvContent, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: `informe_equipos_servidores_ad_gf_chile_${generatedAtFile}.csv`,
    },
  },
}];

const fs = require('fs');
const path = require('path');

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function readText(filePath) {
  return fs.readFileSync(filePath, 'utf8').replace(/^\uFEFF/, '');
}

function render(template, values) {
  return String(template || '').replace(/{{\s*([\w.]+)\s*}}/g, (_, key) => {
    const parts = key.split('.');
    let value = values;
    for (const part of parts) value = value?.[part];
    return value === undefined || value === null ? '' : String(value);
  });
}

